126→        if (-not $detectedUsername) {
127→            if ($remoteUrl -match 'git@[^:]+:([^/]+)/') {
128→                $detectedUsername = $matches[1]
129→            } elseif ($remoteUrl -match 'https://[^/]+/([^/]+)/') {
130→                $detectedUsername = $matches[1]
131→            }
132→        }
133→    }
134→}
