193→        throw "SSH key generation failed"
194→    }
195→    $script:keygenDone = $true
196→    Write-Host "SSH key generated successfully!"
197→
198→    # Start SSH agent and add key
199→    Write-Host "Starting SSH agent and adding key..."
200→    $platform = Get-Platform
201→    $agentOk = $false
202→    if ($platform -eq "windows") {
203→        $agentService = Get-Service ssh-agent -ErrorAction SilentlyContinue
204→        if ($agentService) {
205→            if ($agentService.StartType -eq 'Disabled') {
206→                # Try to enable the service (requires admin)
207→                try {
208→                    Set-Service ssh-agent -StartupType Manual -ErrorAction Stop
209→                } catch {
210→                    Write-Host "Warning: ssh-agent service is disabled. Run as Administrator to enable it." -ForegroundColor Yellow
211→                }
212→            }
213→            if ($agentService.Status -ne 'Running') {
214→                try {
215→                    Start-Service ssh-agent -ErrorAction Stop
216→                } catch {
217→                    Write-Host "Warning: Could not start ssh-agent service. Run as Administrator to start it." -ForegroundColor Yellow
218→                }
219→            }
220→            # Re-check status
221→            $agentService = Get-Service ssh-agent -ErrorAction SilentlyContinue
222→            if ($agentService -and $agentService.Status -eq 'Running') {
223→                $agentOk = $true
224→            }
225→        } else {
226→            Write-Host "Warning: OpenSSH ssh-agent service not found. Install OpenSSH optional feature." -ForegroundColor Yellow
227→        }
228→    } else {
229→        if (-not $env:SSH_AUTH_SOCK) {
230→            $agentOutput = & ssh-agent -s 2>&1
231→            foreach ($line in $agentOutput) {
232→                if ($line -match '(\w+)=([^;]+)') {
233→                    [Environment]::SetEnvironmentVariable($matches[1], $matches[2])
234→                }
235→            }
236→        }
237→        $agentOk = $true
238→    }
239→    if ($agentOk) {
240→        & ssh-add $script:keyPath
241→    } else {
242→        Write-Host "Skipping ssh-add (agent not running). SSH will use the key from config directly." -ForegroundColor Yellow
243→    }
