245→    # SSH config
246→    $configFile = Join-Path $sshDir "config"
247→    if (-not (Test-Path $configFile)) {
248→        New-Item -ItemType File -Path $configFile -Force | Out-Null
249→    }
250→
251→    $defaultHostName = $hostnames[$option]
252→
253→    $customHost = Read-Host "Do you want to add custom host name? (Y/N)"
254→    if ($customHost -match '^[Yy]') {
255→        do {
256→            $hostName = Read-Host "Enter your host name (e.g., work.github.com)"
257→        } while (-not (Test-NoSpaces -Value $hostName -Label "Host name"))
258→    } else {
259→        $hostName = $defaultHostName
260→    }
261→
262→    $configContent = Get-Content $configFile -Raw -ErrorAction SilentlyContinue
263→    if ($configContent -and $configContent -match "Host\s+$([regex]::Escape($hostName))(\s|$)") {
264→        Write-Host "Host '$hostName' already exists in config!"
265→        $replaceChoice = Read-Host "Do you want to replace it? (Y/N)"
266→        if ($replaceChoice -match '^[Yy]') {
267→            # Remove existing host block (Host line + indented lines that follow)
268→            $escapedHost = [regex]::Escape($hostName)
269→            $configContent = $configContent -replace "(?m)\r?\nHost\s+$escapedHost\s*\r?\n(?:\s+.+\r?\n)*", "`n"
270→            $configContent = $configContent -replace "(?m)^Host\s+$escapedHost\s*\r?\n(?:\s+.+\r?\n)*", ""
271→            Set-Content -Path $configFile -Value $configContent.TrimEnd() -NoNewline
272→        } else {
273→            Write-Host "Skipping SSH config update."
274→        }
275→    }
276→
277→    if (-not ($replaceChoice) -or ($replaceChoice -match '^[Yy]')) {
278→        $configBlock = @"
279→
280→Host $hostName
281→  HostName $defaultHostName
282→  AddKeysToAgent yes
283→  IdentityFile ~/.ssh/$keyName
284→"@
285→        Add-Content -Path $configFile -Value $configBlock
286→        Write-Host "SSH config updated successfully!"
287→    }
288→
289→    # Optional git config setup (per-key, using includeIf)
290→    $configGit = Read-Host "Do you want to configure git username and email for this key? (Y/N)"
291→    if ($configGit -match '^[Yy]') {
292→        $defaultUsername = if ($detectedUsername) { $detectedUsername } else { ($email -split '@')[0] }
293→        $gitUsername = Read-Host "Enter your git username [$defaultUsername]"
294→        if ([string]::IsNullOrWhiteSpace($gitUsername)) { $gitUsername = $defaultUsername }
295→
296→        $gitconfigFile = Join-Path $sshDir ".gitconfig-$keyName"
297→        @"
298→[user]
299→    name = $gitUsername
300→    email = $email
301→"@ | Set-Content -Path $gitconfigFile
302→
303→        $includeHost = if ($hostName -ne $defaultHostName) { $hostName } else { $defaultHostName }
304→        & git config --global "includeIf.hasconfig:remote.*.url:git@${includeHost}:*/**" ".path" $gitconfigFile
305→        & git config --global "includeIf.hasconfig:remote.*.url:ssh://git@${includeHost}/**" ".path" $gitconfigFile
306→
307→        Write-Host "Git config for this key saved to $gitconfigFile"
308→        Write-Host "  user.name  = $gitUsername"
309→        Write-Host "  user.email = $email"
310→        Write-Host "  (applied automatically for repos with $includeHost remotes)"
311→    } else {
312→        Write-Host "Skipping git config setup."
313→    }
314→
315→    # Copy to clipboard
316→    $pubKeyPath = "$($script:keyPath).pub"
317→    $pubKey = Get-Content $pubKeyPath -Raw
318→
319→    switch ($platform) {
320→        "windows" {
321→            $pubKey | Set-Clipboard
322→            Write-Host "SSH public key copied to clipboard!"
323→        }
324→        "macos" {
325→            $pubKey | & pbcopy
326→            Write-Host "SSH public key copied to clipboard!"
327→        }
328→        default {
329→            if (Get-Command xclip -ErrorAction SilentlyContinue) {
330→                $pubKey | & xclip -selection clipboard
331→                Write-Host "SSH public key copied to clipboard!"
332→            } elseif (Get-Command clip.exe -ErrorAction SilentlyContinue) {
333→                $pubKey | & clip.exe
334→                Write-Host "SSH public key copied to clipboard!"
335→            } else {
336→                Write-Host "Warning: Could not copy to clipboard automatically."
337→                Write-Host "Please copy the following SSH public key manually:"
338→            }
339→        }
340→    }
341→
342→    Write-Host ""
343→    Write-Host "SSH Public Key:"
344→    Write-Host $pubKey
345→    Write-Host ""
346→
347→    # Open settings page
348→    $settingsUrl = $settingsUrls[$option]
349→    Write-Host "Opening SSH settings page in your browser..."
350→    switch ($platform) {
351→        "windows" { Start-Process $settingsUrl }
352→        "macos"   { & open $settingsUrl }
353→        default {
354→            if (Get-Command xdg-open -ErrorAction SilentlyContinue) {
355→                & xdg-open $settingsUrl 2>&1 | Out-Null
356→                Write-Host "Browser opened successfully!"
357→            } else {
358→                Write-Host "Could not automatically open browser."
359→                Write-Host "Please manually visit: $settingsUrl"
360→            }
361→        }
362→    }
363→
364→    # SSH connection test loop
365→    Write-Host ""
366→    Write-Host "Add the SSH key to your Git provider, then test the connection."
367→    while ($true) {
368→        $choice = Read-Host "Press T to test SSH key, or any other key to exit"
369→        Write-Host ""
370→
371→        if ($choice -match '^[Tt]') {
372→            Write-Host "Testing SSH connection to git@$hostName..."
373→            $sshOutput = & ssh -T -i $script:keyPath -o StrictHostKeyChecking=accept-new -o BatchMode=yes "git@$hostName" 2>&1
374→            $exitCode = $LASTEXITCODE
375→            $outputStr = $sshOutput -join "`n"
376→
377→            if ($exitCode -eq 0 -or $exitCode -eq 1 -or $outputStr -match "successfully authenticated|Shell access is not supported") {
378→                # Filter out confusing Azure DevOps messages
379→                $filteredOutput = ($sshOutput | Where-Object { $_ -notmatch "shell request failed|Shell access is not supported" }) -join "`n"
380→                if ($filteredOutput.Trim()) {
381→                    Write-Host $filteredOutput
382→                }
383→                Write-Host "SSH connection successful! Your SSH key is working." -ForegroundColor Green
384→            } else {
385→                Write-Host $outputStr
386→                Write-Host "SSH connection failed. Please check your SSH key setup." -ForegroundColor Red
387→            }
388→        } else {
389→            Write-Host "Exiting script. SSH setup complete!"
390→            break
391→        }
392→        Write-Host ""
393→    }
394→
395→    # Completion message
396→    Write-Host ""
397→    Write-Host "==========================================="
398→    Write-Host "SSH Setup Complete!"
399→    Write-Host "==========================================="
400→    Write-Host "SSH key generated: $keyName"
401→    Write-Host "SSH key added to agent"
402→    Write-Host "SSH config updated"
403→    Write-Host "Public key copied to clipboard (if supported)"
404→    Write-Host ""
405→    Write-Host "Next steps:"
406→    Write-Host "1. Add the public key to your Git provider"
407→    Write-Host "2. Test the connection using the 'T' option above"
408→    Write-Host ""
409→
410→} catch {
411→    Write-Host "Error: $_" -ForegroundColor Red
412→    exit 1
413→} finally {
414→    # Restore original directory
415→    Set-Location $script:originalDir
416→    # Cleanup partial key files on failure
417→    if ($script:keygenStarted -and -not $script:keygenDone -and $script:keyPath) {
418→        Write-Host "Cleaning up partial SSH key files..."
419→        Remove-Item -Path $script:keyPath -ErrorAction SilentlyContinue
420→        Remove-Item -Path "$($script:keyPath).pub" -ErrorAction SilentlyContinue
421→    }
422→}
